from flask import Flask, request, jsonify, abort
from flask_login import login_required, current_user

app = Flask(__name__)

@app.route('/update_profile', methods=['POST'])
@login_required
def update_profile():
    allowed_fields = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']
    data = request.json or {}
    
    # Filter out only the fields that are allowed to be updated
    updates = {key: value for key, value in data.items() if key in allowed_fields}
    
    # Update user attributes
    for field, value in updates.items():
        setattr(current_user, field, value)
    
    # Save changes (assuming there's a save method or equivalent in your User model)
    current_user.save()
    
    return jsonify({"message": "Profile updated successfully", "updated_fields": list(updates.keys())}), 200

